import React, { useState, useContext } from 'react';
import AdminLayout from '../../components/Layouts/AdminLayout';
import { DataContext } from '../../context/DataContext';
import { AuthContext } from '../../context/AuthContext';
import { JOB_ROLES, INCOME_TYPES, ROLES } from '../../utils/helpers';

const TaskManager = () => {
  const { tasks, staffList, addTask, disciplineTypes } = useContext(DataContext);
  const { user } = useContext(AuthContext);

  const [newTask, setNewTask] = useState({
    title: '',
    assigneeId: '',
    startTime: '',
    deadline: '',
    jobRole: JOB_ROLES[0],
    incomeType: INCOME_TYPES[0],
    disciplineId: '',
  });

  // Chỉ Operational Admin (hoặc Chief) mới được giao việc (Yêu cầu 1)
  const canAssign = user.role === ROLES.OPERATIONAL_ADMIN || user.role === ROLES.CHIEF_ADMIN;

  // Lọc danh sách kỷ luật đã được duyệt (Approved)
  const approvedDisciplines = disciplineTypes.filter(d => d.status === 'Approved');

  const handleAssign = (e) => {
    e.preventDefault();
    if (!canAssign) return alert('Bạn không có quyền giao việc!');
    addTask(newTask);
    alert('Giao việc thành công!');
    setNewTask({ ...newTask, title: '', assigneeId: '' });
  };

  return (
    <AdminLayout>
      <div className="p-4">
        <h2 className="text-2xl font-bold mb-4">Quản lý Nhiệm vụ</h2>
        
        {canAssign && (
          <div className="bg-white p-4 rounded shadow mb-6">
            <h3 className="font-bold mb-2">Giao việc mới</h3>
            <form onSubmit={handleAssign} className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block mb-1">Tên công việc</label>
                <input required type="text" className="border p-2 w-full"
                  value={newTask.title} onChange={e => setNewTask({...newTask, title: e.target.value})} />
              </div>
              
              <div>
                <label className="block mb-1">Nhân sự thực hiện</label>
                <select required className="border p-2 w-full"
                  value={newTask.assigneeId} onChange={e => setNewTask({...newTask, assigneeId: e.target.value})}>
                  <option value="">-- Chọn nhân sự --</option>
                  {staffList.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
              </div>

              <div>
                <label className="block mb-1">Ngày giờ bắt đầu</label>
                <input required type="datetime-local" className="border p-2 w-full"
                  value={newTask.startTime} onChange={e => setNewTask({...newTask, startTime: e.target.value})} />
              </div>

              <div>
                <label className="block mb-1">Ngày giờ kết thúc (Deadline)</label>
                <input required type="datetime-local" className="border p-2 w-full"
                  value={newTask.deadline} onChange={e => setNewTask({...newTask, deadline: e.target.value})} />
              </div>

              <div>
                <label className="block mb-1">Vai trò thực hiện</label>
                <select className="border p-2 w-full"
                  value={newTask.jobRole} onChange={e => setNewTask({...newTask, jobRole: e.target.value})}>
                  {JOB_ROLES.map(r => <option key={r} value={r}>{r}</option>)}
                </select>
              </div>

              <div>
                <label className="block mb-1">Loại thu nhập</label>
                <select className="border p-2 w-full"
                  value={newTask.incomeType} onChange={e => setNewTask({...newTask, incomeType: e.target.value})}>
                  {INCOME_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                </select>
              </div>

              <div className="md:col-span-2">
                <label className="block mb-1 text-red-600">Hình thức kỷ luật (nếu vi phạm)</label>
                <select required className="border p-2 w-full border-red-200 bg-red-50"
                  value={newTask.disciplineId} onChange={e => setNewTask({...newTask, disciplineId: e.target.value})}>
                  <option value="">-- Chọn hình thức kỷ luật --</option>
                  {approvedDisciplines.map(d => (
                    <option key={d.id} value={d.id}>{d.name}</option>
                  ))}
                </select>
                <small className="text-gray-500">*Chỉ hiển thị các hình thức đã được Regulatory Admin duyệt.</small>
              </div>

              <button type="submit" className="bg-blue-600 text-white p-2 rounded col-span-2">Giao việc</button>
            </form>
          </div>
        )}

        <div className="bg-white p-4 rounded shadow">
          <h3 className="font-bold mb-2">Danh sách công việc đang chạy</h3>
          <table className="w-full border-collapse">
            <thead>
              <tr className="bg-gray-100 text-left">
                <th className="p-2 border">Công việc</th>
                <th className="p-2 border">Nhân sự</th>
                <th className="p-2 border">Deadline</th>
                <th className="p-2 border">Trạng thái</th>
              </tr>
            </thead>
            <tbody>
              {tasks.map(task => {
                const staff = staffList.find(s => s.id == task.assigneeId);
                return (
                  <tr key={task.id} className="border-b">
                    <td className="p-2">{task.title}</td>
                    <td className="p-2">{staff?.name}</td>
                    <td className="p-2">{new Date(task.deadline).toLocaleString()}</td>
                    <td className="p-2">
                      <span className={`px-2 py-1 rounded text-xs ${task.status === 'Overdue' ? 'bg-red-200 text-red-800' : 'bg-green-200 text-green-800'}`}>
                        {task.status}
                      </span>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </AdminLayout>
  );
};

export default TaskManager;
